import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  ProductionOrderDto,
  ProductionOrderFilter,
  CreateProductionOrderDto,
  UpdateProductionOrderDto,
  PagedResult,
  BomDto,
  BomFilter,
  CreateBomDto,
  UpdateBomDto,
  ProductionStageDto,
  CreateProductionStageDto,
  UpdateProductionStageDto,
  StageFilter,
  StageTrackingDto,
  StageTrackingFilter,
} from './models';

const BASE = '/mes';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export const sxEndpoint = {
  getProductionOrders: async (filter?: ProductionOrderFilter) => {
    const qs = buildQs({
      status: filter?.status,
      teamId: filter?.teamId,
      fromDate: filter?.fromDate,
      toDate: filter?.toDate,
      searchText: filter?.searchText,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<PagedResult<ProductionOrderDto>>>(
      `${BASE}/production-orders?${qs}`,
    );
    return unwrap(res);
  },

  getProductionOrder: async (id: string) => {
    const res = await apiClient.get<BffResponse<ProductionOrderDto>>(`${BASE}/production-orders/${id}`);
    return unwrap(res);
  },

  createProductionOrder: async (dto: CreateProductionOrderDto) => {
    const res = await apiClient.post<BffResponse<ProductionOrderDto>>(`${BASE}/production-orders`, dto);
    return unwrap(res);
  },

  updateProductionOrder: async (id: string, dto: UpdateProductionOrderDto) => {
    const res = await apiClient.put<BffResponse<ProductionOrderDto>>(`${BASE}/production-orders/${id}`, dto);
    return unwrap(res);
  },

  releaseProductionOrder: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/production-orders/${id}/release`);
    return unwrap(res);
  },

  completeProductionOrder: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/production-orders/${id}/complete`);
    return unwrap(res);
  },

  getBoms: async (filter?: BomFilter) => {
    const qs = buildQs({
      productCode: filter?.productCode,
      isActive: filter?.isActive,
      searchText: filter?.searchText,
    });
    const res = await apiClient.get<BffResponse<BomDto[]>>(`${BASE}/boms?${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getBom: async (id: string) => {
    const res = await apiClient.get<BffResponse<BomDto>>(`${BASE}/boms/${id}`);
    return unwrap(res);
  },

  createBom: async (dto: CreateBomDto) => {
    const res = await apiClient.post<BffResponse<BomDto>>(`${BASE}/boms`, dto);
    return unwrap(res);
  },

  updateBom: async (id: string, dto: UpdateBomDto) => {
    const res = await apiClient.put<BffResponse<BomDto>>(`${BASE}/boms/${id}`, dto);
    return unwrap(res);
  },

  deleteBom: async (id: string) => {
    await apiClient.delete(`${BASE}/boms/${id}`);
  },

  getStages: async (filter?: StageFilter) => {
    const qs = buildQs({ searchText: filter?.searchText });
    const url = qs ? `${BASE}/stages?${qs}` : `${BASE}/stages`;
    const res = await apiClient.get<BffResponse<ProductionStageDto[]>>(url);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  createStage: async (dto: CreateProductionStageDto) => {
    const res = await apiClient.post<BffResponse<ProductionStageDto>>(`${BASE}/stages`, dto);
    return unwrap(res);
  },

  updateStage: async (id: string, dto: UpdateProductionStageDto) => {
    const res = await apiClient.put<BffResponse<ProductionStageDto>>(`${BASE}/stages/${id}`, dto);
    return unwrap(res);
  },

  deleteStage: async (id: string) => {
    await apiClient.delete(`${BASE}/stages/${id}`);
  },

  getStageTracking: async (filter?: StageTrackingFilter) => {
    const qs = buildQs({
      productionOrderId: filter?.productionOrderId,
      stageId: filter?.stageId,
      fromDate: filter?.fromDate,
      toDate: filter?.toDate,
      status: filter?.status,
      searchText: filter?.searchText,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 50,
    });
    const res = await apiClient.get<BffResponse<PagedResult<StageTrackingDto>>>(
      `${BASE}/stage-tracking?${qs}`,
    );
    return unwrap(res);
  },

  qcApproveStageTracking: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/stage-tracking/${id}/qc-approve`);
    return unwrap(res);
  },

  qcRejectStageTracking: async (id: string, reason: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(
      `${BASE}/stage-tracking/${id}/qc-reject`,
      reason,
    );
    return unwrap(res);
  },
};
